@pytest.fixture
def user_factory(db):
    created = []
    def _create(**kwargs):
        defaults = {"name": "Test User", "email": f"user{len(created)}@example.com"}
        defaults.update(kwargs)
        user = User(**defaults)
        db.add(user)
        created.append(user)
        return user
    yield _create
    for u in created:
        db.delete(u)
